INSERT INTO `exam_questions_v3` VALUES (1,1,'JavaScript',NULL,'choice','关于 let 和 var 的区别，以下说法正确的是？','{\"options\": [\"let 有块级作用域，var 没有\", \"let 和 var 完全相同\", \"let 不能重复声明，var 可以\", \"let 会提升，var 不会\"]}','{\"correct\": 0, \"explanation\": \"let 有块级作用域且不能重复声明，var 是函数作用域且可以重复声明\"}',1,0.95,NULL,1,'agent',NULL,1781163995000,1781163995000),(2,1,'JavaScript',NULL,'choice','以下哪个方法会改变原数组？','{\"options\": [\"map()\", \"filter()\", \"sort()\", \"slice()\"]}','{\"correct\": 2, \"explanation\": \"sort() 会改变原数组，map/filter/slice 返回新数组\"}',2,0.90,NULL,1,'agent',NULL,1781163995000,1781163995000),(3,1,'JavaScript',NULL,'coding','实现一个防抖函数 debounce(fn, delay)','{\"template\": \"function debounce(fn, delay) {\\n  // 你的代码\\n}\", \"testCases\": [{\"input\": \"连续调用3次间隔100ms delay=300ms\", \"expected\": \"只执行最后一次\"}]}','{\"solution\": \"function debounce(fn, delay) { let timer; return function(...args) { clearTimeout(timer); timer = setTimeout(() => fn.apply(this, args), delay); }; }\"}',3,0.85,NULL,1,'agent',NULL,1781163995000,1781163995000),(4,1,'React',NULL,'choice','React Hooks 中 useEffect 第二个参数为空数组意味着什么？','{\"options\": [\"每次渲染都执行\", \"只在组件挂载时执行一次\", \"不执行\", \"只在卸载时执行\"]}','{\"correct\": 1, \"explanation\": \"空数组表示没有依赖项，只在 mount 时执行一次\"}',2,0.92,NULL,1,'agent',NULL,1781163995000,1781163995000),(5,1,'React',NULL,'choice','以下哪个不是 React Hooks 的规则？','{\"options\": [\"只能在函数组件顶层调用\", \"不能在循环条件中调用\", \"只能在自定义Hook中调用\", \"不能在普通JS函数中调用\"]}','{\"correct\": 2, \"explanation\": \"Hooks 可以在函数组件和自定义 Hook 中调用，不限于自定义 Hook\"}',2,0.88,NULL,1,'agent',NULL,1781163995000,1781163995000),(6,1,'CSS',NULL,'choice','CSS Grid 中 grid-template-columns: 1fr 2fr 1fr 表示什么？','{\"options\": [\"三列等宽\", \"第一列和第三列等宽 第二列是它们的两倍\", \"第二列最小\", \"三列自适应\"]}','{\"correct\": 1, \"explanation\": \"fr 单位按比例分配 1:2:1 表示中间列是两侧的两倍\"}',1,0.93,NULL,1,'agent',NULL,1781163995000,1781163995000),(7,1,'Python',NULL,'choice','Python 中列表推导式 [x**2 for x in range(5)] 的结果是？','{\"options\": [\"[0,1,4,9,16]\", \"[1,4,9,16,25]\", \"[0,2,4,6,8]\", \"Error\"]}','{\"correct\": 0, \"explanation\": \"range(5) 是 0-4，平方后为 [0,1,4,9,16]\"}',1,0.97,NULL,1,'agent',NULL,1781163995000,1781163995000),(8,2,NULL,NULL,'choice','字节跳动前端面试：解释事件循环 Event Loop 机制','{\"options\": [\"调用栈->微任务队列->宏任务队列\", \"调用栈->宏任务队列->微任务队列\", \"微任务->调用栈->宏任务\", \"宏任务->微任务->调用栈\"]}','{\"correct\": 0, \"explanation\": \"先执行调用栈，清空后执行微任务队列，再取一个宏任务执行\"}',3,0.80,NULL,0,'manual',NULL,1781163995000,1781163995000);
